var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"쳇...... 아무리 치워도 끝이 없네.","JPN":"ちくしょう……倒しても倒してもキリがない。","ENG":"Bah, they just won't stop coming!","TWN":"嘖……不管怎麼處理都處理不完這些源源不盡的臭東西啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"정말이지 화단청소보다 지긋지긋한 녀석들이라니까.","JPN":"ほんと、花壇の掃除よりうんざりするやつらだぜ。","ENG":"These guys are worse than cleaning the flowerbeds.","TWN":"真是比清掃花壇更讓人厭煩啊。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"학교 근방은 거의 정리가 끝난 것 같군.","JPN":"学校付近の侵食体はほぼ片付いたようだ。","ENG":"It seems the school perimeter is clear now.","TWN":"學校附近好像已經清理完畢了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그리고 두 사람.","JPN":"あと、君たち二人。","ENG":"And you two.","TWN":"另外妳們兩個。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"약속했듯이, 성실하게 선도부의 업무를 도운 공로로 지각한 죄는 묻지 않겠다.","JPN":"約束したとおり、真面目に風紀委員会の仕事を手伝ってくれたので\\n遅刻した罪は問わないでおく。","ENG":"As I promised, I won't punish you for your tardiness since you helped us Student Guides fulfill our duty.","TWN":"按照我們之前的約定，妳們幫助先鋒部隊的功勞抵消了妳們遲到的處罰。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"하지만 건전한 학창생활은 교칙을 준수하는 데에서 시작한다는 사실을 잊지 말도록.","JPN":"しかし、健全な学校生活は校則を守ることから始まるということを忘れないように。","ENG":"But I hope you won't forget that all students are to follow the rules.","TWN":"但是請不要忘記：良好的學生生活是從遵守校規開始的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"네에...... 네......","JPN":"はいはい。","ENG":"Yes, ma'am...","TWN":"是，是，沒錯。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"선도부장은 항상 변함없네.","JPN":"風紀委員長は変わらないね。","ENG":"Student Guide Leader, you never change.","TWN":"先鋒部隊長真的跟平常一樣呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"당연하다. 학생회장이 부재 중이니만큼, 선도부가 더욱 굳건히 소임을 다해야지.","JPN":"当然だ。生徒会長の不在は風紀委員会が役目を果たして埋めないと。","ENG":"Of course not. We Student Guides must work harder on behalf of the Student President until she returns.","TWN":"當然，因為學生會長不在啊，所以先鋒部隊應該更加堅定地履行職責才行。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아......","JPN":"あ……","ENG":"Oh...","TWN":"啊..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"너무 염려하지 마라.","JPN":"そう心配するな。","ENG":"But don't worry.","TWN":"不要這麼擔心。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"학생회장이 선택한 길이다. 다른 학생들이 자기 때문에 마음 아파하는 모습은 보고 싶어하지 않을 거다.","JPN":"生徒会長が選んだ道だ。他の生徒たちが自分のせいで悲しむ姿は見たくないだろう。","ENG":"She left of her own accord. She wouldn't want the others to be sad because of her.","TWN":"這是學生會長她選擇的道路，她肯定不會希望看到其他學生為了她感到難過。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그래. 선도부장 말이 맞아. 예전부터 그렇게 제멋대로 남을 돕고 다녔으니까.","JPN":"そう。風紀委員長の言うとおりよ。昔からそうやって勝手に人を助けていたから。","ENG":"The Student Guide Leader is right. She always liked to help people, whether they wanted it or not.","TWN":"是啊，先鋒部隊長說得沒錯，畢竟她從以前就喜歡到處幫助他人。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"음. 말이 아니라 행동이 앞서는 자세는 확실히 학생회장으로서 모범적이었지.","JPN":"そうだな。言葉より先に行動をする姿勢は、確かに生徒会長として模範的だった。","ENG":"Mm... She was a definitely exemplary leader, doing things first and thinking later.","TWN":"嗯，而且不是只在嘴上說說，而是親身用行動去實踐，作為學生會長她真的是大家的模範。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그런데 유진. 안타깝지만 교칙에 따르면 반려동물은 교실에 들일 수 없다.","JPN":"ところでシロコ。残念だが、校則でペットは教室に連れて入れない。","ENG":"By the way, Eujin. I'm sorry, but you can't bring pets into your classroom. It's the rule.","TWN":"對了，劉珍，雖然很遺憾，但是根據校規，寵物是不能帶進校園的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어, 정말? 그럼 얜 어쩌지?","JPN":"え、本当か？　じゃあ、こいつはどうすればいいんだ？","ENG":"Err, really? Then, what should we do with him?","TWN":"欸，真的嗎？那牠該怎麼辦？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"크흠. 다행히도 선도부실은 지금 나를 제외하면 사용하는 사람이 없다.","JPN":"こほん。幸い、風紀委員会室は私の他に誰も使う者がいない。","ENG":"Ahem... Fortunately for him, I'm the only one who's using the Student Guide Room at this moment.","TWN":"嗯，幸好現在先鋒部隊室裡除了我之外沒有人在使用。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그러니 네가 동의한다면, 선도부실에 데려다 놓고 돌봐 줘도......","JPN":"だから君さえよければ、風紀委員会室に置いて世話をしても……","ENG":"So, if you agree, I can keep him there—","TWN":"如果妳同意的話，可以把牠送到先鋒部隊室裡交給我照顧……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEVIATHAN_RIVAL_NULL_NULL","text":{"KOREA":"비켜비켜♪ 앞에 있다 콩하면 아프다구~♪","JPN":"どいてどいて♪　ぶつかると痛いよ～♪","ENG":"Outta the way! Outta the way! ♪ Or you're going to get hurt! ♪","TWN":"閃開啊~通通閃開♪ 檔在前面被撞到的話會很痛的~通通閃開♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L30_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"으아앗!","JPN":"うわ！","ENG":"Waah!","TWN":"啊啊——！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_18"},{"id":"L31_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"부, 부딪칠 뻔 했잖아! 조심하라고!","JPN":"ぶ、ぶつかるところだったじゃねえか！　気をつけろ！","ENG":"Hey, watch! You almost bumped into me!","TWN":"差、差點就被撞到了! 小心點啊！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"거기 정지! 곧 조회 시간인데 어딜 가는 거냐!","JPN":"そこ、止まれ！　もうすぐ朝礼の時間なのにどこに行くんだ！","ENG":"Hey, stop right there! It'll be a morning assembly soon. Where do you think you're going?","TWN":"停下來！就要開朝會了，妳這是要去哪裡!"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEVIATHAN_RIVAL_NULL_NULL","text":{"KOREA":"아하하~♪ 그런 명령으론 ███ 님의 스피드를 따라잡지 못할걸~♪","JPN":"あはは～♪　そんな命令では███様のスピードに追いつけないよ～♪","ENG":"Ah hah hah! ♪ Orders like that can't stop ███!♪","TWN":"啊哈哈哈~♪妳這種命令是追不上██的速度的~♪"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"이건......","JPN":"これは……","ENG":"This...","TWN":"這個..."},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"내가...... 잘못 본 건 아니겠지?","JPN":"私が……見間違えたのではないですよね？","ENG":"I'm not seeing things... or am I?","TWN":"是我看錯了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"캐시! 지금 발랄한 학교 생활 영상이나 볼 때가 아냐!","JPN":"キャシー！　今は楽しい学校生活の映像なんか見てる場合じゃない！","ENG":"Cathy! This is not the time to watch student videos!","TWN":"凱西！現在不是看那些青春洋溢的學校生活影片的時候！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"기다려요. 영상 뒤쪽을 확인하고 있었는데 정말 이상한 내용이 나왔거든요.","JPN":"待ってください。映像の後半を見ていたら、本当におかしい内容だったんです。","ENG":"Wait. I was just checking the later parts of the video, and I found something that didn't make sense.","TWN":"等等...我只是在確認影片的最後一部分，裡面出現了很奇怪的內容。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아이리는 어디 있죠? 같이 보면서 확인해야 할 것 같은데?","JPN":"アイリはどこですか？\\n一緒に見ながら確認しないと……","ENG":"Where's Irie? She needs to see this.","TWN":"艾莉去哪了？這應該要她來確認一下吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"뭐가 됐든 지금은 나중에! 그 괴물 녀석들이 방해 전파로 우리 다이브를 막은 것 같아!","JPN":"とりあえず後にしろ！　あの怪物どもが妨害電波で私たちのダイブを塞いだみたいだ！","ENG":"Whatever it is, it has to wait. I think those monsters have jammed our signals and blocked us from diving.","TWN":"不管怎麼，這都之後再說！！妳們看，這些怪物好像用干擾電波阻擋了我們的躍入!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아까보다 훨씬 더 많이 몰려올 거야!","JPN":"さっきより大量に押し寄せてくる！","ENG":"There will be more of them here soon!","TWN":"而且數量比之前更多了!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};